fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let enabled = required_bool(params, "enabled").map_err(anyhow::Error::msg)?;
    let fft = required_f32(params, "fft").map_err(anyhow::Error::msg)?;
    let dry = required_f32(params, "dry").map_err(anyhow::Error::msg)?;
    let wet = required_f32(params, "wet").map_err(anyhow::Error::msg)?;
    let g_out = required_f32(params, "g_out").map_err(anyhow::Error::msg)?;
    let ihc = required_f32(params, "ihc").map_err(anyhow::Error::msg)?;
    let itc = required_f32(params, "itc").map_err(anyhow::Error::msg)?;
    let ifi = required_f32(params, "ifi").map_err(anyhow::Error::msg)?;
    let ifo = required_f32(params, "ifo").map_err(anyhow::Error::msg)?;
    let ils = required_bool(params, "ils").map_err(anyhow::Error::msg)?;
    let cs = required_f32(params, "cs").map_err(anyhow::Error::msg)?;
    let mk = required_f32(params, "mk").map_err(anyhow::Error::msg)?;
    let pd = required_f32(params, "pd").map_err(anyhow::Error::msg)?;
    let wpp = required_bool(params, "wpp").map_err(anyhow::Error::msg)?;
    let eqv = required_bool(params, "eqv").map_err(anyhow::Error::msg)?;
    let lcm = required_f32(params, "lcm").map_err(anyhow::Error::msg)?;
    let lcf = required_f32(params, "lcf").map_err(anyhow::Error::msg)?;
    let eq_0 = required_f32(params, "eq_0").map_err(anyhow::Error::msg)?;
    let eq_1 = required_f32(params, "eq_1").map_err(anyhow::Error::msg)?;
    let eq_2 = required_f32(params, "eq_2").map_err(anyhow::Error::msg)?;
    let eq_3 = required_f32(params, "eq_3").map_err(anyhow::Error::msg)?;
    let eq_4 = required_f32(params, "eq_4").map_err(anyhow::Error::msg)?;
    let eq_5 = required_f32(params, "eq_5").map_err(anyhow::Error::msg)?;
    let eq_6 = required_f32(params, "eq_6").map_err(anyhow::Error::msg)?;
    let eq_7 = required_f32(params, "eq_7").map_err(anyhow::Error::msg)?;
    let hcm = required_f32(params, "hcm").map_err(anyhow::Error::msg)?;
    let hcf = required_f32(params, "hcf").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_ENABLED, if enabled { 1.0 } else { 0.0 }),
        (PORT_CTRL_FFT, fft),
        (PORT_CTRL_DRY, dry),
        (PORT_CTRL_WET, wet),
        (PORT_CTRL_G_OUT, g_out),
        (PORT_CTRL_IHC, ihc),
        (PORT_CTRL_ITC, itc),
        (PORT_CTRL_IFI, ifi),
        (PORT_CTRL_IFO, ifo),
        (PORT_CTRL_ILS, if ils { 1.0 } else { 0.0 }),
        (PORT_CTRL_CS, cs),
        (PORT_CTRL_MK, mk),
        (PORT_CTRL_PD, pd),
        (PORT_CTRL_WPP, if wpp { 1.0 } else { 0.0 }),
        (PORT_CTRL_EQV, if eqv { 1.0 } else { 0.0 }),
        (PORT_CTRL_LCM, lcm),
        (PORT_CTRL_LCF, lcf),
        (PORT_CTRL_EQ_0, eq_0),
        (PORT_CTRL_EQ_1, eq_1),
        (PORT_CTRL_EQ_2, eq_2),
        (PORT_CTRL_EQ_3, eq_3),
        (PORT_CTRL_EQ_4, eq_4),
        (PORT_CTRL_EQ_5, eq_5),
        (PORT_CTRL_EQ_6, eq_6),
        (PORT_CTRL_EQ_7, eq_7),
        (PORT_CTRL_HCM, hcm),
        (PORT_CTRL_HCF, hcf),
    ];

    match layout {
        AudioChannelLayout::Mono => {
            let processor = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT], control_ports)?;
            Ok(BlockProcessor::Mono(Box::new(processor)))
        }
        AudioChannelLayout::Stereo => {
            let left = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT], control_ports)?;
            let right = lv2::build_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_IN], &[PORT_AUDIO_OUT_OUT], control_ports)?;
            Ok(BlockProcessor::Stereo(Box::new(DualMonoProcessor { left, right })))
        }
    }
}

struct DualMonoProcessor { left: lv2::Lv2Processor, right: lv2::Lv2Processor }
impl StereoProcessor for DualMonoProcessor {
    fn process_frame(&mut self, input: [f32; 2]) -> [f32; 2] {
        [self.left.process_sample(input[0]), self.right.process_sample(input[1])]
    }
}

fn schema() -> Result<ModelParameterSchema> { Ok(model_schema()) }

